const childWorkflows = ['CWF-110', 'CWF-120', 'CWF-130', 'CWF-140'];
let executionPlan = { workflows_to_execute: childWorkflows, current_index: 0, status: 'PLANNING', decisions: {} };
return [{ json: { ...$json, execution_plan: executionPlan, pack_orchestration: { started_at: new Date().toISOString(), expected_duration_seconds: 120 } } }];

const childResults = { CWF_110: $json.cwf110_result, CWF_120: $json.cwf120_result, CWF_130: $json.cwf130_result, CWF_140: $json.cwf140_result };
const allHealthy = Object.values(childResults).every(r => r?.status === 'SUCCESS' || r?.status === 'COMPLETED');
const topicFinalized = $json.cwf140_result?.payload?.research_synthesis_finalized === true;
const validationOk = allHealthy && topicFinalized;
return [{ json: { ...$json, pack_validation: { child_results_aggregated: childResults, all_children_healthy: allHealthy, topic_finalized: topicFinalized, validation_ok: validationOk, route_to_error: !validationOk } } }];

if ($json.pack_validation.route_to_error) return [];
return [{
  json: {
    ...$json,
    dossier_write: {
      mutation_type: 'namespace_update',
      target: 'dossier.discovery',
      timestamp: new Date().toISOString(),
      writer_id: 'WF-100',
      pack_context: $json.pack_context,
      child_results: $json.pack_validation.child_results_aggregated,
      audit_entry: 'topic-intelligence-pack-completion from WF-100'
    }
  }
}];

if ($json.pack_validation.route_to_error) return [];
return [{
  json: {
    ...$json,
    se_route_runs_write: {
      operation: 'record_pack_execution',
      pack_id: 'WF-100',
      dossier_id: $json.dossier_id,
      child_workflows_executed: ['CWF-110', 'CWF-120', 'CWF-130', 'CWF-140'],
      execution_status: 'COMPLETED',
      topic_finalized: $json.pack_validation.topic_finalized,
      timestamp: new Date().toISOString()
    }
  }
}];

if ($json.pack_validation.route_to_error) return [];
return [{
  json: {
    workflow_id: 'WF-100',
    execution_status: 'SUCCESS',
    completion_packet: {
      instance_id: 'WF-100-COMP-' + Date.now(),
      artifact_family: 'topic_intelligence_result',
      schema_version: '1.0.0',
      producer_workflow: 'WF-100',
      dossier_ref: $json.dossier_id,
      created_at: new Date().toISOString(),
      status: 'CREATED',
      payload: {
        pack_executed: 'WF-100',
        topic_finalized: $json.pack_validation.topic_finalized,
        next_workflow: 'WF-200',
        child_packets: ['CWF-110_output', 'CWF-120_output', 'CWF-130_output', 'CWF-140_output']
      }
    }
  }
}];

if (!$json.pack_validation.route_to_error) return [];
return [{
  json: {
    workflow_id: 'WF-100',
    routing_decision: 'ERROR',
    route_to_workflow: 'WF-900',
    error_message: 'Pack validation failed or child workflow failed',
    failure_context: $json.pack_validation,
    child_results: $json.pack_validation.child_results_aggregated
  }
}];
